// memoize via /scratch/answers.json — second call is a file read
let key = cache_key(&question);
let cache = read_cache();                 // /scratch/answers.json

if let Some(text) = cache.get(&key) {
    return Ok(text.clone());              // hit — no model call
}

let text = generate_answer(&model, &question).await?;
let mut cache = read_cache();
cache.insert(key, text.clone());

fs::write(
    "/scratch/answers.json",
    serde_json::to_vec(&cache).map_err(|e| e.to_string())?,
).map_err(|e| e.to_string())?;
Ok(text)
